<?php
namespace Tests\Feature;
use App\Models\User;use App\Services\ExamService;use App\Services\ReportService;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Http\UploadedFile;use Illuminate\Support\Facades\DB;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Facades\RateLimiter;use Illuminate\Support\Facades\Redis;use Tests\TestCase;
class CompletionFlowTest extends TestCase {use RefreshDatabase;protected bool $seed=true;private function student():User{return User::where('username','siswa')->first();}private function examSession():object{return app(ExamService::class)->start($this->student(),1,'LATIHAN','127.0.0.1','phpunit');}public function test_server_received_timestamp_wins_and_queue_recovers():void{$service=app(ExamService::class);$s=$this->examSession();$q=DB::table('bank_soals')->first();$ops=DB::table('opsi_jawabans')->where('bank_soal_id',$q->id)->orderBy('id')->get();Redis::del("queue_jawaban:$s->id");$service->save($s,$q->id,$ops[0]->id,null,'2099-01-01T00:00:00Z');$service->flushOne($s->id,$q->id);$first=DB::table('jawaban_siswas')->where(['sesi_ujian_id'=>$s->id,'bank_soal_id'=>$q->id])->first();usleep(10000);$service->save($s,$q->id,$ops[1]->id,null,'2000-01-01T00:00:00Z');$this->assertNotNull(Redis::hget("queue_jawaban:$s->id",(string)$q->id));$service->flushOne($s->id,$q->id);$latest=DB::table('jawaban_siswas')->where(['sesi_ujian_id'=>$s->id,'bank_soal_id'=>$q->id])->first();$this->assertSame($ops[1]->id,$latest->opsi_jawaban_id);$this->assertGreaterThan($first->server_updated_at,$latest->server_updated_at);$this->assertFalse(Redis::hget("queue_jawaban:$s->id",(string)$q->id));}public function test_stale_buffer_cannot_overwrite_newer_database_answer():void{$service=app(ExamService::class);$s=$this->examSession();$q=DB::table('bank_soals')->first();$ops=DB::table('opsi_jawabans')->where('bank_soal_id',$q->id)->orderBy('id')->get();DB::table('jawaban_siswas')->insert(['sesi_ujian_id'=>$s->id,'bank_soal_id'=>$q->id,'opsi_jawaban_id'=>$ops[1]->id,'tipe_soal'=>'PG','skor'=>0,'scoring_status'=>'auto_scored','server_updated_at'=>now()->addMinute(),'created_at'=>now(),'updated_at'=>now()]);Redis::hset("queue_jawaban:$s->id",(string)$q->id,json_encode(['sesi_ujian_id'=>$s->id,'user_id'=>$s->user_id,'bank_soal_id'=>$q->id,'opsi_jawaban_id'=>$ops[0]->id,'jawaban_essay'=>null,'tipe_soal'=>'PG','client_updated_at'=>null,'server_updated_at'=>now()->subMinute()->toISOString()]));$service->flushOne($s->id,$q->id);$this->assertSame($ops[1]->id,DB::table('jawaban_siswas')->first()->opsi_jawaban_id);}public function test_web_login_and_logout_are_audited():void{$this->post('/login',['username'=>'siswa','password'=>'siswa123'])->assertRedirectContains('/dashboard?auth_refresh=');$this->post('/logout')->assertRedirect('/login');$this->assertDatabaseHas('audit_logs',['action'=>'web_login']);$this->assertDatabaseHas('audit_logs',['action'=>'web_logout']);}public function test_report_includes_target_student_who_never_entered_exam():void{DB::table('users')->insert(['username'=>'absen','name'=>'Belum Masuk','email'=>'absen@cbt.local','password'=>bcrypt('secret123'),'role'=>'Siswa','kelas_aktif_id'=>1,'status_kehadiran'=>'alpha','created_at'=>now(),'updated_at'=>now()]);$rows=app(ReportService::class)->rows(1);$stats=app(ReportService::class)->stats($rows);$this->assertSame(2,$stats['total_target']);$this->assertSame(2,$stats['belum_masuk']);$this->assertSame('belum_masuk',$rows->firstWhere('username','absen')->status);}public function test_empty_package_cannot_be_finalized():void{$guru=User::where('username','guru')->first();$id=DB::table('paket_soals')->insertGetId(['mata_pelajaran_id'=>1,'pembuat_user_id'=>$guru->id,'judul'=>'Draft Kosong','status'=>'draft','created_at'=>now(),'updated_at'=>now()]);$this->post('/login',['username'=>'guru','password'=>'guru123']);$this->post("/kelola/paket/$id/ready")->assertStatus(422);}public function test_teacher_can_import_question_csv_and_preview_package():void{$guru=User::where('username','guru')->first();$id=DB::table('paket_soals')->insertGetId(['mata_pelajaran_id'=>1,'pembuat_user_id'=>$guru->id,'judul'=>'Import','status'=>'draft','created_at'=>now(),'updated_at'=>now()]);$csv="tipe_soal,pertanyaan,bobot,opsi_a,opsi_b,opsi_c,opsi_d,opsi_e,kunci_pg\nPG,Soal impor,2,Salah,Benar,,,,B\n";$this->post('/login',['username'=>'guru','password'=>'guru123']);$level=ob_get_level();$this->post("/kelola/paket/$id/import-soal",['file'=>UploadedFile::fake()->createWithContent('soal.csv',$csv)])->assertRedirect();while(ob_get_level()>$level)ob_end_clean();$this->assertDatabaseHas('bank_soals',['paket_soal_id'=>$id,'pertanyaan'=>'Soal impor']);$this->get("/kelola/paket/$id/preview")->assertOk()->assertSee('Soal impor');while(ob_get_level()>$level)ob_end_clean();}public function test_admin_can_create_update_and_delete_unused_master():void{$this->post('/login',['username'=>'admin','password'=>'admin123']);$this->get('/kelola')->assertOk();$this->post('/kelola/rombel',['nama_rombel'=>'TEMP'])->assertRedirect();$id=DB::table('rombels')->where('nama_rombel','TEMP')->value('id');$this->put("/kelola/master/rombel/$id",['nama_rombel'=>'TEMP2'])->assertRedirect();$this->assertDatabaseHas('rombels',['nama_rombel'=>'TEMP2']);$this->delete("/kelola/master/rombel/$id")->assertRedirect();$this->assertDatabaseMissing('rombels',['id'=>$id]);}public function test_manual_grade_cannot_exceed_question_weight():void{$s=$this->examSession();$q=DB::table('bank_soals')->first();$id=DB::table('jawaban_siswas')->insertGetId(['sesi_ujian_id'=>$s->id,'bank_soal_id'=>$q->id,'tipe_soal'=>'ISIAN','skor'=>0,'scoring_status'=>'pending_manual','created_at'=>now(),'updated_at'=>now()]);$this->post('/login',['username'=>'guru','password'=>'guru123']);$this->post("/kelola/grade/$id",['skor'=>999])->assertStatus(422);}public function test_student_cannot_open_management_panel():void{$this->post('/login',['username'=>'siswa','password'=>'siswa123']);$this->get('/kelola')->assertForbidden();}public function test_reports_export_json_xlsx_and_pdf():void{$this->post('/login',['username'=>'superadmin','password'=>'superadmin123']);$this->get('/kelola/laporan/1/json')->assertOk()->assertJsonPath('data.statistik.total_target',1);$this->get('/kelola/laporan/1/xlsx')->assertOk();$this->get('/kelola/laporan/1/pdf')->assertOk();}public function test_api_login_is_rate_limited():void{RateLimiter::clear('127.0.0.1');for($i=0;$i<10;$i++)$this->postJson('/api/v1/auth/login',['username'=>'nobody','password'=>'bad']);$this->postJson('/api/v1/auth/login',['username'=>'nobody','password'=>'bad'])->assertStatus(429);}public function test_api_login_and_logout_are_audited():void{$token=$this->postJson('/api/v1/auth/login',['username'=>'siswa','password'=>'siswa123'])->assertOk()->json('data.token');$this->withHeaders(['Authorization'=>'Bearer '.$token])->postJson('/api/v1/auth/logout')->assertOk();$this->assertDatabaseHas('audit_logs',['action'=>'api_login']);$this->assertDatabaseHas('audit_logs',['action'=>'api_logout']);}public function test_superadmin_sees_user_and_feature_management_and_can_update_access():void{$this->post('/login',['username'=>'superadmin','password'=>'superadmin123'])->assertRedirectContains('/dashboard?auth_refresh=');$this->get('/dashboard')->assertRedirect('/vue/dashboard/superadmin');$this->get('/kelola')->assertOk();$role=\Spatie\Permission\Models\Role::where('name','Pengawas')->first();$this->put("/kelola/role/$role->id/permissions",['permissions'=>['monitor-exams','view-reports']])->assertRedirect();$this->assertTrue($role->fresh()->hasPermissionTo('view-reports'));}public function test_api_permission_matrix_controls_module_access():void{$guru=\App\Models\User::where('username','guru')->first();$guru->syncRoles(['Guru']);$role=\Spatie\Permission\Models\Role::where('name','Guru')->first();$role->revokePermissionTo('manage-questions');$token=$this->postJson('/api/v1/auth/login',['username'=>'guru','password'=>'guru123'])->json('data.token');$this->withHeaders(['Authorization'=>'Bearer '.$token])->getJson('/api/v1/guru/paket-soal')->assertForbidden();$role->givePermissionTo('manage-questions');app(\Spatie\Permission\PermissionRegistrar::class)->forgetCachedPermissions();$this->assertTrue($role->fresh()->hasPermissionTo('manage-questions'));$this->app['auth']->forgetGuards();$token2=$this->postJson('/api/v1/auth/login',['username'=>'guru','password'=>'guru123'])->assertOk()->json('data.token');$this->withHeaders(['Authorization'=>'Bearer '.$token2])->getJson('/api/v1/guru/paket-soal')->assertOk();}public function test_api_created_user_receives_spatie_role_relation():void{$token=$this->postJson('/api/v1/auth/login',['username'=>'superadmin','password'=>'superadmin123'])->assertOk()->json('data.token');$this->withHeaders(['Authorization'=>'Bearer '.$token])->postJson('/api/v1/admin/users',['username'=>'pengawas_api','name'=>'Pengawas API','password'=>'secret123','role'=>'Pengawas'])->assertOk();$this->assertTrue(User::where('username','pengawas_api')->first()->hasRole('Pengawas'));}}
